async function sendRoleChat(){ const message=$("chatInput").value.trim(); if(!message) throw new Error("请输入消息"); const body={title:$("chatSessionTitle").value||"角色对话",message,character_ids:state.selectedRoleIds,conversation_id:state.currentConversationId,chat_type:$("chatType").value,sender_name:$("senderName").value||"你",sender_profile:$("senderProfile").value,required_responder_ids:$("requiredResponderIds").value.split(/[,，\s]+/).filter(Boolean),reply_mode:$("replyMode").value,narrator_enabled:$("narratorEnabled").checked}; const data=await api("/api/roleplay/chat",{method:"POST",body:JSON.stringify(body)}); connectTask(data.task_id, payload=>{ const result=(payload.data||{}).result; if(result&&result.messages){ state.currentConversationId=result.conversation_id; state.chatMessages=result.messages; $("chatInput").value=""; renderChatMessages(); loadRoles().catch(()=>{}); } }); selectSection("tasks"); }
