async function saveAgentEmbedding(){ const settings={novel_generation_mode:$("agentGenerationMode").value,agent_skills_enabled:$("agentSkillsEnabled").checked,agent_runtime_backend:$("agentRuntimeBackend").value,retrieval_backend:$("retrievalBackend").value,framework_auto_fallback:$("frameworkAutoFallback").checked,embedding_base_url:$("embeddingBaseUrl").value,embedding_api_key:$("embeddingApiKey").value,embedding_model:$("embeddingModel").value,agent_web_enabled:$("agentWebEnabled").checked,agent_web_endpoint:$("agentWebEndpoint").value,agent_web_api_key:$("agentWebApiKey").value,agent_web_max_results:Number($("agentWebMaxResults").value||5)}; await api("/api/settings/agent-embedding",{method:"PUT",headers:{"X-Sensitive-Ticket":state.sensitiveTicket},body:JSON.stringify({settings})}); $("embeddingApiKey").value=""; $("agentWebApiKey").value=""; toast("Agent/Embedding 设置已保存"); }
