async function loadTokens(){ const data=await api("/api/token-log"); const sum=(data.summary||{}).totals||{}; $("tokenSummary").innerHTML=[['总输入',sum.prompt_tokens||0],['总输出',sum.completion_tokens||0],['总计',sum.total_tokens||0],['记录数',data.total||0]].map(([k,v])=>`<div class="metric-card"><span>${k}</span><b>${v}</b></div>`).join(""); const rows=data.entries||[]; $("tokenTable").innerHTML=`<table><thead><tr><th>时间</th><th>操作</th><th>模型</th><th>输入</th><th>输出</th><th>总计</th><th>预览</th></tr></thead><tbody>${rows.map(r=>`<tr><td>${escapeHtml(r.timestamp)}</td><td>${escapeHtml(r.operation)}</td><td>${escapeHtml(r.model)}</td><td>${r.prompt_tokens??"-"}</td><td>${r.completion_tokens??"-"}</td><td>${r.total_tokens??"-"}</td><td>${escapeHtml(r.content_preview||"")}</td></tr>`).join("")}</tbody></table>`; }
