async function loadTasks(){ const data=await api("/api/tasks"); const tasks=data.tasks||[]; const list=$("taskList"); list.innerHTML=""; if(!tasks.length){ list.innerHTML='<div class="notice small">暂无任务历史</div>'; return; } for(const t of tasks){ const row=document.createElement("div"); row.className="item-card task-row"; const status=`${t.status||""} · ${t.stage||""} · ${t.progress||0}%`; row.innerHTML=`<span><strong>${escapeHtml(t.name||t.task_id)}</strong><small>${escapeHtml(status)}${t.error?` · ${escapeHtml(t.error)}`:""}</small></span><span class="task-actions"><button type="button" data-act="detail">详情</button>${t.status==="running"?'<button type="button" data-act="cancel">取消</button>':""}${t.retryable&&["failed","cancelled"].includes(t.status)?'<button type="button" data-act="retry">重试</button>':""}</span>`; row.querySelector('[data-act="detail"]').onclick=ev=>{ ev.stopPropagation(); showTaskDetail(t.task_id).catch(e=>toast(e.message)); }; const cancel=row.querySelector('[data-act="cancel"]'); if(cancel) cancel.onclick=ev=>{ ev.stopPropagation(); cancelTask(t.task_id).catch(e=>toast(e.message)); }; const retry=row.querySelector('[data-act="retry"]'); if(retry) retry.onclick=ev=>{ ev.stopPropagation(); retryTask(t.task_id).catch(e=>toast(e.message)); }; row.onclick=()=>showTaskDetail(t.task_id).catch(e=>toast(e.message)); list.appendChild(row); } }
async function showTaskDetail(id){ const data=await api(`/api/tasks/${enc(id)}`); $("taskDetail").textContent=JSON.stringify(data.task||{},null,2); }
async function cancelTask(id){ const data=await api(`/api/tasks/${enc(id)}/cancel`,{method:"POST",body:"{}"}); toast(data.ok?"任务已请求取消":"任务不可取消或已结束"); await loadTasks(); }
async function retryTask(id){ const data=await api(`/api/tasks/${enc(id)}/retry`,{method:"POST",body:"{}"}); toast("已提交重试任务"); connectTask(data.task_id); await loadTasks(); }
async function loadDiagnostics(){ const data=await api("/api/diagnostics"); $("taskDetail").textContent=JSON.stringify(data,null,2); }
async function exportDiagnostics(){ const data=await api("/api/diagnostics/export",{method:"POST",body:"{}"}); addDownload(data.download); toast("诊断信息已生成下载"); selectSection("write"); selectWorkspace("snapshots"); }
function connectTask(id, onPayload){ if(state.eventSource) state.eventSource.close(); state.streamBuffer=""; $("streamText").textContent=""; state.eventSource=new EventSource(`/api/tasks/${enc(id)}/events?token=${enc(state.token)}`); const h=e=>{ const payload=JSON.parse(e.data); updateTask(payload); if(onPayload) onPayload(payload); }; for(const t of ["started","progress","completed","failed","cancelled","finished"]) state.eventSource.addEventListener(t,h); }
function updateTask(p){ const d=p.data||{}; const percent=Number(d.progress||(p.type==="completed"?100:0)); $("taskStage").textContent=d.stage||p.type; $("taskPercent").textContent=`${percent}%`; $("taskBar").style.width=`${percent}%`; $("taskMessage").textContent=p.message||""; if(d.text){ state.streamBuffer=(state.streamBuffer+d.text).slice(-10000); $("streamText").textContent=state.streamBuffer; } if(d.result){ $("streamText").textContent=typeof d.result==="string"?d.result:JSON.stringify(d.result,null,2); } if(["completed","failed","cancelled"].includes(p.type)&&state.eventSource){ state.eventSource.close(); loadTasks().catch(()=>{}); } }
